
/* ── Floating container ── */
.nge-chat-float[data-v-519c8e58] {
  position: fixed;
  bottom: 36px;
  right: 8px;
  z-index: 9000;
  display: flex;
  flex-direction: column;
  background: transparent;
  border-radius: 6px;
  overflow: hidden;
  font-family: 'Inter', 'Roboto', sans-serif;
}
.nge-chat-float--collapsed[data-v-519c8e58] {
  width: auto !important;
  height: auto !important;
  background: rgba(10, 14, 24, 0.6);
}
.nge-chat-float--dragging[data-v-519c8e58] {
  user-select: none;
}

/* ── Resize handle — top-left corner ── */
.nge-chat-resize[data-v-519c8e58] {
  position: absolute;
  top: 0;
  left: 0;
  width: 12px;
  height: 12px;
  cursor: nw-resize;
  z-index: 10;
}
.nge-chat-resize[data-v-519c8e58]::after {
  content: '';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 5px;
  height: 5px;
  border-top: 1px solid rgba(255, 255, 255, 0.15);
  border-left: 1px solid rgba(255, 255, 255, 0.15);
}

/* ── Tiny control strip (drag handle + buttons) ── */
.nge-chat-strip[data-v-519c8e58] {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 2px 6px;
  cursor: grab;
  user-select: none;
  flex-shrink: 0;
}
.nge-chat-strip[data-v-519c8e58]:active { cursor: grabbing;
}
.nge-chat-strip-dot[data-v-519c8e58] {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #444;
  flex-shrink: 0;
}
.nge-chat-strip-dot--on[data-v-519c8e58] {
  background: #0fb18b;
  box-shadow: 0 0 4px rgba(15, 177, 139, 0.5);
}
.nge-chat-strip-badge[data-v-519c8e58] {
  background: #4a9eff;
  color: #fff;
  font-size: 9px;
  font-weight: 700;
  padding: 0 4px;
  border-radius: 6px;
  min-width: 14px;
  text-align: center;
  line-height: 14px;
}
.nge-chat-strip-spacer[data-v-519c8e58] { flex: 1;
}
.nge-chat-strip-btn[data-v-519c8e58] {
  background: none;
  border: none;
  color: #556;
  font-size: 12px;
  cursor: pointer;
  padding: 0 2px;
  line-height: 1;
  transition: color 0.12s;
}
.nge-chat-strip-btn[data-v-519c8e58]:hover { color: #aaa;
}

/* ── Messages wrapper with fade ── */
.nge-chat-messages-wrap[data-v-519c8e58] {
  flex: 1;
  position: relative;
  min-height: 0;
  overflow: hidden;
}

/* Background gradient: opaque at bottom (contrast for text) → transparent at top */
.nge-chat-fade[data-v-519c8e58] {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 100%;
  background: linear-gradient(to top, rgba(8,10,20,0.88) 0%, rgba(8,10,20,0.65) 30%, rgba(8,10,20,0.3) 60%, transparent 100%);
  pointer-events: none;
  z-index: 1;
}
.nge-chat-messages[data-v-519c8e58] {
  height: 100%;
  overflow-y: auto;
  display: flex;
  flex-direction: column-reverse;
  padding: 2px 8px;
  position: relative;
  z-index: 2;
}
.nge-chat-messages[data-v-519c8e58]::-webkit-scrollbar { width: 2px;
}
.nge-chat-messages[data-v-519c8e58]::-webkit-scrollbar-track { background: transparent;
}
.nge-chat-messages[data-v-519c8e58]::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.08); border-radius: 2px;
}
.nge-chat-messages-inner[data-v-519c8e58] {
  display: flex;
  flex-direction: column;
  gap: 0;
}

/* ── Message line — inline name + text ── */
.nge-chat-msg[data-v-519c8e58] {
  padding: 2px 4px;
  line-height: 1.4;
  font-size: 13px;
}
.nge-chat-msg[data-v-519c8e58]:hover { background: rgba(255, 255, 255, 0.03); border-radius: 3px;
}
.nge-chat-msg-trophy[data-v-519c8e58] { font-size: 10px; margin-right: 1px;
}
.nge-chat-msg-name[data-v-519c8e58] {
  font-weight: 600;
  font-size: 13px;
  margin-right: 4px;
}
.nge-chat-msg-text[data-v-519c8e58] {
  color: #b0b8c8;
}
.nge-chat-link[data-v-519c8e58] {
  color: #4a9eff;
  text-decoration: none;
  word-break: break-all;
  font-size: 13px;
}
.nge-chat-link[data-v-519c8e58]:hover { text-decoration: underline;
}

/* System messages */
.nge-chat-sys[data-v-519c8e58] {
  font-size: 11px;
  color: #556;
  font-style: italic;
  padding: 0 4px;
}
.nge-chat-sys--warn[data-v-519c8e58] { color: #c08030;
}

/* Time separator */
.nge-chat-time-sep[data-v-519c8e58] {
  text-align: center;
  padding: 2px 0;
}
.nge-chat-time-sep span[data-v-519c8e58] {
  font-size: 10px;
  color: #556;
  padding: 0 6px;
}

/* New messages banner */
.nge-chat-new-banner[data-v-519c8e58] {
  position: absolute;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%);
  background: rgba(74, 158, 255, 0.8);
  color: #fff;
  font-size: 9px;
  font-weight: 700;
  padding: 2px 10px;
  border-radius: 8px;
  cursor: pointer;
  z-index: 5;
}
.nge-chat-new-banner[data-v-519c8e58]:hover { background: rgba(74, 158, 255, 1);
}
.nge-chat-banner-enter-active[data-v-519c8e58] { transition: opacity 0.15s;
}
.nge-chat-banner-leave-active[data-v-519c8e58] { transition: opacity 0.12s;
}
.nge-chat-banner-enter-from[data-v-519c8e58],
.nge-chat-banner-leave-to[data-v-519c8e58] { opacity: 0;
}

/* ── Input ── */
.nge-chat-input-wrap[data-v-519c8e58] {
  padding: 3px 4px;
  flex-shrink: 0;
}
.nge-chat-input[data-v-519c8e58] {
  width: 100%;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(100, 180, 255, 0.1);
  border-radius: 4px;
  padding: 5px 8px;
  color: #e0e4ec;
  font-size: 13px;
  font-family: inherit;
  outline: none;
  transition: border-color 0.12s;
  box-sizing: border-box;
}
.nge-chat-input[data-v-519c8e58]:focus { border-color: rgba(74, 158, 255, 0.3);
}
.nge-chat-input[data-v-519c8e58]::placeholder { color: #445;
}
.nge-chat-input[data-v-519c8e58]:disabled { opacity: 0.3;
}

/* Empty state */
.nge-chat-empty[data-v-519c8e58] {
  text-align: center;
  padding: 16px 8px;
  color: #556;
  font-size: 12px;
}
