
.nge-ann-panel[data-v-4d633747] {
  position: fixed;
  bottom: 48px;
  right: 16px;
  width: 340px;
  background: rgba(18, 22, 30, 0.97);
  border: 1px solid rgba(100, 180, 255, 0.25);
  border-radius: 8px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.6),
              0 0 0 1px rgba(100, 180, 255, 0.08);
  z-index: 500;
  font-size: 15px;
  color: #cdd;
  backdrop-filter: blur(8px);
  animation: nge-ann-slide-in-4d633747 0.18s ease;
}
@keyframes nge-ann-slide-in-4d633747 {
from { opacity: 0; transform: translateY(12px);
}
to   { opacity: 1; transform: translateY(0);
}
}

/* ── Header ── */
.nge-ann-header[data-v-4d633747] {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 10px 8px 12px;
}
.nge-ann-brain[data-v-4d633747] { font-size: 18px;
}
.nge-ann-title[data-v-4d633747] {
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: rgba(100, 180, 255, 0.7);
  font-weight: 600;
}
.nge-ann-id[data-v-4d633747] {
  font-family: monospace;
  font-size: 13px;
  color: #8bf;
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.nge-ann-copy[data-v-4d633747] {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 12px;
  opacity: 0.5;
  padding: 0 2px;
  line-height: 1;
}
.nge-ann-copy[data-v-4d633747]:hover { opacity: 1;
}
.nge-ann-saved[data-v-4d633747] {
  font-size: 12px;
  color: #7f8;
  animation: nge-ann-fade-4d633747 1.2s ease forwards;
}
@keyframes nge-ann-fade-4d633747 {
0%   { opacity: 1;
}
70%  { opacity: 1;
}
100% { opacity: 0;
}
}
.nge-ann-close[data-v-4d633747] {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  line-height: 1;
  color: #888;
  padding: 0 2px;
}
.nge-ann-close[data-v-4d633747]:hover { color: #fff;
}
.nge-ann-divider[data-v-4d633747] {
  height: 1px;
  background: rgba(100, 180, 255, 0.12);
  margin: 0 12px;
}

/* ── Rows ── */
.nge-ann-row[data-v-4d633747] {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  min-height: 36px;
}
.nge-ann-label[data-v-4d633747] {
  font-size: 13px;
  color: #778;
  min-width: 60px;
}

/* ── Status ── */
.nge-ann-status[data-v-4d633747] {
  flex: 1;
  font-weight: 600;
  font-size: 14px;
}
.nge-ann-status--complete[data-v-4d633747]   { color: #CE93D8;
}
.nge-ann-status--inprogress[data-v-4d633747] { color: #aaa;
}
.nge-ann-status--loading[data-v-4d633747]    { color: #778; font-style: italic;
}
.nge-ann-status--error[data-v-4d633747]      { color: #f88;
}

/* ── Edit stats (PCG merge/split counts) ── */
.nge-ann-edit-stats[data-v-4d633747] {
  display: flex;
  align-items: center;
  gap: 14px;
  flex: 1;
}
.nge-ann-edit-stat[data-v-4d633747] {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 14px;
  font-weight: 600;
}
.nge-ann-edit-stat--merge[data-v-4d633747] { color: #CE93D8;
}
.nge-ann-edit-stat--split[data-v-4d633747] { color: #f5a623;
}
.nge-ann-edit-icon[data-v-4d633747] {
  width: 14px;
  height: 14px;
}
.nge-ann-edit-contributors[data-v-4d633747] {
  font-size: 12px;
  color: #778;
  margin-left: auto;
}
.nge-ann-edit-loading[data-v-4d633747] {
  font-size: 13px;
  color: #778;
  font-style: italic;
}

/* ── Buttons ── */
.nge-ann-btn[data-v-4d633747] {
  padding: 5px 12px;
  border-radius: 4px;
  border: 1px solid rgba(100, 180, 255, 0.3);
  background: rgba(100, 180, 255, 0.08);
  color: #8bf;
  font-size: 14px;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.12s, color 0.12s;
}
.nge-ann-btn[data-v-4d633747]:hover:not(:disabled) {
  background: rgba(100, 180, 255, 0.18);
  color: #adf;
}
.nge-ann-btn[data-v-4d633747]:disabled { opacity: 0.4; cursor: default;
}
.nge-ann-btn--small[data-v-4d633747] { padding: 3px 8px;
}

/* ── Cell type ── */
.nge-ann-row--type[data-v-4d633747] { align-items: flex-start;
}
.nge-ann-type-wrap[data-v-4d633747] {
  position: relative;
  flex: 1;
}
.nge-ann-type-toggle[data-v-4d633747] {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 10px;
  border-radius: 4px;
  border: 1px solid rgba(100, 180, 255, 0.25);
  background: rgba(100, 180, 255, 0.06);
  color: #aac;
  font-size: 14px;
  cursor: pointer;
  text-align: left;
}
.nge-ann-type-toggle[data-v-4d633747]:hover:not(:disabled) { background: rgba(100, 180, 255, 0.14);
}
.nge-ann-type-toggle--open[data-v-4d633747] { border-color: rgba(100, 180, 255, 0.5);
}
.nge-ann-chevron[data-v-4d633747] { opacity: 0.5; margin-left: 6px;
}
.nge-ann-type-menu[data-v-4d633747] {
  position: absolute;
  left: 0;
  bottom: calc(100% + 4px);
  width: 100%;
  background: #1a1f2a;
  border: 1px solid rgba(100, 180, 255, 0.25);
  border-radius: 6px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.6);
  z-index: 600;
  max-height: 240px;
  overflow-y: auto;
  padding: 4px 0;
}
.nge-ann-type-item[data-v-4d633747] {
  display: block;
  width: 100%;
  padding: 7px 12px;
  background: none;
  border: none;
  color: #bcc;
  font-size: 14px;
  text-align: left;
  cursor: pointer;
}
.nge-ann-type-item[data-v-4d633747]:hover { background: rgba(100,180,255,0.1); color: #fff;
}
.nge-ann-type-item--active[data-v-4d633747] { color: #7f8; font-weight: 600;
}
.nge-ann-type-divider[data-v-4d633747] { height: 1px; background: rgba(100,180,255,0.1); margin: 4px 0;
}
.nge-ann-type-custom[data-v-4d633747] {
  display: flex;
  gap: 6px;
  padding: 6px 10px;
}
.nge-ann-type-input[data-v-4d633747] {
  flex: 1;
  padding: 4px 9px;
  border-radius: 4px;
  border: 1px solid rgba(100,180,255,0.25);
  background: rgba(255,255,255,0.05);
  color: #cdd;
  font-size: 13px;
  outline: none;
}
.nge-ann-type-input[data-v-4d633747]:focus { border-color: rgba(100,180,255,0.5);
}

/* ── Help / second opinion ── */
.nge-ann-row--help[data-v-4d633747] { justify-content: center;
}
.nge-ann-help-btn[data-v-4d633747] {
  background: none;
  border: 1px solid rgba(245, 166, 35, 0.25);
  border-radius: 4px;
  padding: 6px 14px;
  color: #f5a623;
  font-size: 14px;
  cursor: pointer;
  transition: background 0.12s;
  width: 100%;
}
.nge-ann-help-btn[data-v-4d633747]:hover { background: rgba(245, 166, 35, 0.08);
}
.nge-ann-issue-label[data-v-4d633747] {
  font-size: 12px;
  color: #778;
  margin-bottom: 6px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}
.nge-ann-issue-chips[data-v-4d633747] {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  margin-bottom: 8px;
}
.nge-ann-issue-chip[data-v-4d633747] {
  padding: 5px 12px;
  border-radius: 12px;
  border: 1px solid rgba(245, 166, 35, 0.2);
  background: rgba(245, 166, 35, 0.04);
  color: #b89050;
  font-size: 13px;
  cursor: pointer;
  transition: all 0.12s;
}
.nge-ann-issue-chip[data-v-4d633747]:hover { background: rgba(245, 166, 35, 0.1);
}
.nge-ann-issue-chip--active[data-v-4d633747] {
  background: rgba(245, 166, 35, 0.18);
  border-color: rgba(245, 166, 35, 0.5);
  color: #f5a623;
  font-weight: 600;
}
.nge-ann-help-form[data-v-4d633747] {
  padding: 6px 12px 10px;
}
.nge-ann-help-note[data-v-4d633747] {
  width: 100%;
  box-sizing: border-box;
  padding: 6px 8px;
  border-radius: 4px;
  border: 1px solid rgba(100, 180, 255, 0.25);
  background: rgba(255, 255, 255, 0.04);
  color: #cdd;
  font-size: 14px;
  resize: vertical;
  outline: none;
  font-family: inherit;
}
.nge-ann-help-note[data-v-4d633747]:focus { border-color: rgba(100, 180, 255, 0.5);
}
.nge-ann-help-actions[data-v-4d633747] {
  display: flex;
  gap: 6px;
  margin-top: 6px;
  justify-content: flex-end;
}
.nge-ann-btn--ghost[data-v-4d633747] {
  background: none;
  border-color: rgba(255, 255, 255, 0.15);
  color: #888;
}
.nge-ann-btn--ghost[data-v-4d633747]:hover:not(:disabled) { color: #bbb; background: rgba(255,255,255,0.04);
}

/* ── Error ── */
.nge-ann-error[data-v-4d633747] {
  padding: 6px 12px 10px;
  font-size: 12px;
  color: #f88;
  opacity: 0.8;
}
