.chip[data-v-83f26a4c] {
    position: absolute;
    width: auto;
    max-width: 80vw;
    color: #d0e8ff;
    padding: 30px;
    padding-bottom: 20px;
    border-radius: 8px;
    display: grid;
    justify-items: center;
    font-size: 18px;
    font-weight: 300;
    grid-row-gap: 15px;

    border: 1px solid rgba(160, 200, 240, 0.2);
    background: linear-gradient(135deg, rgba(10, 15, 35, 0.78), rgba(20, 12, 45, 0.75));
    backdrop-filter: blur(20px);
    box-shadow: 0 0 20px rgba(80, 140, 255, 0.1);
}

/* Microchip-inspired corner traces */
.corner[data-v-83f26a4c] {
    position: absolute;
    pointer-events: none;
    z-index: 2;
}

/* L-shaped corner bracket */
.corner-tl[data-v-83f26a4c] {
    top: -1px;
    left: -1px;
    width: 20px;
    height: 20px;
    border-top: 1.5px solid rgba(160, 200, 240, 0.55);
    border-left: 1.5px solid rgba(160, 200, 240, 0.55);
}

/* Short trace extending from top-left corner */
.corner-tl[data-v-83f26a4c]::before {
    content: '';
    position: absolute;
    top: -1.5px;
    left: 20px;
    width: 8px;
    height: 0;
    border-top: 1.5px solid rgba(160, 200, 240, 0.3);
}
.corner-tl[data-v-83f26a4c]::after {
    content: '';
    position: absolute;
    top: 20px;
    left: -1.5px;
    width: 0;
    height: 8px;
    border-left: 1.5px solid rgba(160, 200, 240, 0.3);
}
