
/* ── Backdrop ── */
.nge-cmd-backdrop[data-v-e390fd9f] {
  position: fixed;
  inset: 0;
  z-index: 10000;
  background: rgba(0, 0, 0, 0.55);
  display: flex;
  justify-content: center;
  padding-top: 12vh;
  backdrop-filter: blur(2px);
}

/* ── Shell ── */
.nge-cmd-shell[data-v-e390fd9f] {
  width: 560px;
  max-height: 480px;
  background: rgba(18, 22, 30, 0.98);
  border: 1px solid rgba(100, 180, 255, 0.2);
  border-radius: 12px;
  box-shadow:
    0 24px 80px rgba(0, 0, 0, 0.65),
    0 0 0 1px rgba(100, 180, 255, 0.06),
    0 0 60px rgba(74, 158, 255, 0.08);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  animation: nge-cmd-slide-e390fd9f 0.15s cubic-bezier(0.16, 1, 0.3, 1);
}
@keyframes nge-cmd-slide-e390fd9f {
from { opacity: 0; transform: translateY(-8px) scale(0.98);
}
to   { opacity: 1; transform: translateY(0) scale(1);
}
}

/* ── Input ── */
.nge-cmd-input-wrap[data-v-e390fd9f] {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 18px;
  border-bottom: 1px solid rgba(100, 180, 255, 0.1);
}
.nge-cmd-input-icon[data-v-e390fd9f] {
  font-size: 16px;
  color: rgba(74, 158, 255, 0.5);
  flex-shrink: 0;
}
.nge-cmd-input[data-v-e390fd9f] {
  flex: 1;
  background: none;
  border: none;
  outline: none;
  color: #e0e4ec;
  font-size: 16px;
  font-family: inherit;
  caret-color: rgba(74, 158, 255, 0.8);
}
.nge-cmd-input[data-v-e390fd9f]::placeholder { color: #555;
}
.nge-cmd-esc[data-v-e390fd9f] {
  font-size: 10px;
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.06);
  color: #555;
  border: 1px solid rgba(255, 255, 255, 0.08);
  font-family: inherit;
}

/* ── Results ── */
.nge-cmd-results[data-v-e390fd9f] {
  flex: 1;
  overflow-y: auto;
  padding: 6px 0;
  min-height: 0;
  scrollbar-width: thin;
  scrollbar-color: rgba(74, 158, 255, 0.15) transparent;
}
.nge-cmd-category[data-v-e390fd9f] {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: rgba(74, 158, 255, 0.4);
  padding: 10px 18px 4px;
}
.nge-cmd-item[data-v-e390fd9f] {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 18px;
  cursor: pointer;
  transition: background 0.06s;
}
.nge-cmd-item[data-v-e390fd9f]:hover,
.nge-cmd-item--selected[data-v-e390fd9f] {
  background: rgba(74, 158, 255, 0.08);
}
.nge-cmd-item--selected[data-v-e390fd9f] {
  background: rgba(74, 158, 255, 0.12);
}
.nge-cmd-item-icon[data-v-e390fd9f] {
  font-size: 14px;
  width: 24px;
  text-align: center;
  flex-shrink: 0;
}
.nge-cmd-item-text[data-v-e390fd9f] {
  flex: 1;
  min-width: 0;
}
.nge-cmd-item-label[data-v-e390fd9f] {
  font-size: 14px;
  color: #d0d4dc;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.nge-cmd-item--selected .nge-cmd-item-label[data-v-e390fd9f] { color: #fff;
}
.nge-cmd-item-desc[data-v-e390fd9f] {
  font-size: 12px;
  color: #555;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  margin-top: 1px;
}
.nge-cmd-item--selected .nge-cmd-item-desc[data-v-e390fd9f] { color: #777;
}
.nge-cmd-shortcut[data-v-e390fd9f] {
  font-size: 10px;
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.05);
  color: #666;
  border: 1px solid rgba(255, 255, 255, 0.08);
  font-family: inherit;
  white-space: nowrap;
  flex-shrink: 0;
}
.nge-cmd-empty[data-v-e390fd9f] {
  text-align: center;
  padding: 32px 20px;
  color: #444;
  font-size: 13px;
  font-style: italic;
}

/* ── Footer ── */
.nge-cmd-footer[data-v-e390fd9f] {
  display: flex;
  gap: 16px;
  padding: 8px 18px;
  border-top: 1px solid rgba(100, 180, 255, 0.08);
  font-size: 10px;
  color: #444;
}
.nge-cmd-footer kbd[data-v-e390fd9f] {
  font-size: 9px;
  padding: 1px 4px;
  border-radius: 2px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: #555;
  font-family: inherit;
  margin-right: 3px;
}

/* ── Transition ── */
.nge-cmd-fade-enter-active[data-v-e390fd9f] { transition: opacity 0.12s ease;
}
.nge-cmd-fade-leave-active[data-v-e390fd9f] { transition: opacity 0.08s ease;
}
.nge-cmd-fade-enter-from[data-v-e390fd9f],
.nge-cmd-fade-leave-to[data-v-e390fd9f] { opacity: 0;
}
